const r = $('Find Stale Proposals').first().json.report || {};
const proposals = r.proposals || [];
const rows = proposals.map(p => '<tr><td style="padding:8px;border-bottom:1px solid #eee;font-size:13px"><b>'+p.project_name+'</b><br><span style="color:#6b7280;font-size:12px">'+(p.client_name||'?')+' &lt;'+(p.client_email||'?')+'&gt;</span></td><td style="padding:8px;border-bottom:1px solid #eee;font-size:13px;text-align:right">'+Number(p.total_price||0).toLocaleString('es-ES')+' EUR</td><td style="padding:8px;border-bottom:1px solid #eee;font-size:13px;color:#dc2626;text-align:center"><b>'+p.days_waiting+'d</b></td></tr>').join('');
const html = '<div style="font-family:Arial,sans-serif;max-width:680px;margin:0 auto;padding:20px;color:#1f2937">' +
'<h2 style="color:#e67e22">'+r.count+' propuestas sin respuesta del cliente >7d</h2>' +
'<p>Estas propuestas se enviaron hace mas de una semana y siguen sin respuesta del cliente. Considera enviar un follow-up manual o llamar.</p>' +
'<table style="width:100%;border-collapse:collapse;background:white;border-radius:6px;overflow:hidden"><thead style="background:#1f2937;color:white"><tr><th style="padding:8px;text-align:left;font-size:11px">Proyecto / Cliente</th><th style="padding:8px;text-align:right;font-size:11px">Precio</th><th style="padding:8px;text-align:center;font-size:11px">Espera</th></tr></thead><tbody>'+rows+'</tbody></table>' +
'<p style="color:#94a3b8;font-size:11px;margin-top:24px">cron_proposal_response_followup diario 11:00. Solo se envia si hay >0 stale.</p>' +
'</div>';
return [{ json: { html, subject: '[ArquitAI] '+r.count+' propuestas sin respuesta del cliente >7d' } }];
